use regex::Regex;

trait ReplaceEmails {
    fn replace_emails(&self, text: &str) -> String;
}

impl ReplaceEmails for str {
    fn replace_emails(&self, text: &str) -> String {
        let re = Regex::new(r"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\b").unwrap_or_else(|e| panic!("Regex error: {}", e));
        re.replace_all(text, "[REDACTED]").to_string()
    }
}

fn main() {
    let text = "Contact me at foo@example.com or bar@domain.co.uk";
    println!("{}", text.replace_emails(text));
}

